INSERT INTO "Review" ("id", "userId", "name", "educationalInstitution", "rating", "text", "isPublished", "createdAt") VALUES
('cmp67i06u05l5lk9cif9egsas', 'cmp66xizp00irlktg5qkrjbi8', 'Тимофеев Айсен Никитич', 'НПОУ «ЯКИТ», очное отделение, группа КИСП-25, 1 курс', '5', 'Очень понравилось, что нельзя «прокликать» практику бездумно — проверка реально заставляет думать. Курс полностью прошёл, сертификатом доволен.', 't', '2026-04-11 05:55:46.167'),
('cmp67i06v05l9lk9ch4pg09k5', 'cmp66xj5o00ixlktgvngz2w5d', 'Аветисян Рубик Тигранович', 'НПОУ «ЯКИТ», очное отделение, группа КИСП-9-21, 4 курс', '4', 'Как программисту, зашло сочетание «теория + руки». Прошёл полностью. Сертификат пригодится. Не пять звёзд только из‑за пары опечаток в заданиях.', 't', '2026-04-14 09:38:38.891'),
('cmp67i06v05lblk9c5r79krog', 'cmp66xj5t00j0lktgc3rk930x', 'Андреев Айсен Федорович', 'НПОУ «ЯКИТ», очное отделение, группа КИСП-9-21, 4 курс', '4', 'Хорошо стыкуется с тем, что проходим в группе. Прошла все модули, к итоговому документу вопросов нет. Минус балл за то, что AI-подсказки иногда слишком общие.', 't', '2026-04-11 07:58:43.187'),
('cmp67i06w05ldlk9cl8i89pmy', 'cmp66xj5v00j3lktgyab1nb5k', 'Антонов Викториан Гаврилович', 'НПОУ «ЯКИТ», очное отделение, группа КИСП-9-21, 4 курс', '2', 'Дошёл до сертификата, но устал от объёма чтения. Польза есть, но эмоций мало — скорее «отработал норму».', 't', '2026-04-12 05:38:08.082'),
('cmp67i06w05lflk9c9eq3z1b8', 'cmp5md617001ugnc0xyskec06', 'Татаринова Надежда Иннокентьева', 'Якутский гуманитарный колледж, группа КИ-24, 3 курс', '2', 'Дошёл до сертификата, но опыт спорный: часть формулировок сухая, а ожидания по времени на практику занижены. Для галочки сойдёт, восторгом не делюсь.', 't', '2026-04-16 11:55:05.312'),
('cmp67i06x05lhlk9cvi2k3hid', 'cmp66xj5y00j6lktg1jue18k5', 'Асмаков Александр Романович', 'НПОУ «ЯКИТ», очное отделение, группа КИСП-9-21, 4 курс', '2', 'Сертификат есть, но вовлечение среднее: часть модулей ощущались как «прочитай и ответь». Для галочки подойдёт.', 't', '2026-04-11 14:55:46.375'),
('cmp67i06x05ljlk9c9h8i1m0b', 'cmp66xj6100j9lktgeg4milz1', 'Ахметзянов Ренат Артурович', 'НПОУ «ЯКИТ», очное отделение, группа КИСП-9-21, 4 курс', '4', 'Удобно совмещать с работой: чёткие дедлайны по модулям не дают забросить. Сертификат получил. Минус — иногда долгая загрузка страниц, на контент не влияет.', 't', '2026-04-09 17:27:32.958'),
('cmp67i06y05lllk9cqib2cgys', 'cmp66xj6300jclktg3j1bmfoy', 'Бондарь Михаил Владимирович', 'НПОУ «ЯКИТ», очное отделение, группа КИСП-9-21, 4 курс', '4', 'Как программисту, зашло сочетание «теория + руки». Прошёл полностью. Сертификат пригодится. Не пять звёзд только из‑за пары опечаток в заданиях.', 't', '2026-04-15 09:12:41.204'),
('cmp67i07705mhlk9cdk7s3jv6', 'cmp66xjd600kllktg71il51v5', 'Пальшин Артем Алексеевич', 'НПОУ «ЯКИТ», очное отделение, группа КИСП-9-22, 4 курс', '3', 'Прошла полностью на заочке. Нормально, без сюрпризов: тесты, практика, документ. Хотелось бы чуть больше голосовых/видео пояснений, но это вкусовщина.', 't', '2026-04-12 09:21:31.478'),
('cmp67i05f05frlk9cnf2z504o', 'cmp66xht800bflktgzn45s2ni', 'Жирков Петр Афанасьевич', 'НПОУ «ЯКИТ», заочное отделение, группа ЗКИСП-22, 5 курс', '4', 'Как программисту, зашло сочетание «теория + руки». Прошёл полностью. Сертификат пригодится. Не пять звёзд только из‑за пары опечаток в заданиях.', 't', '2026-04-10 17:59:51.048'),
('cmp67i06z05lrlk9c01kj41y6', 'cmp66xj6b00jllktgxmdh1ami', 'Дмитриева Василина Анатольевна', 'НПОУ «ЯКИТ», очное отделение, группа КИСП-9-21, 4 курс', '3', 'Нормальный курс для общей грамотности по ИБ. Всё закрыл, документ выдали. Без восторга, но жаловаться не на что — ровно то, что обещали.', 't', '2026-04-10 03:04:32.472'),
('cmp67i07005ltlk9celudrtf1', 'cmp66xj6d00jolktg9ajkg12j', 'Заболоцкий Антон Константинович', 'НПОУ «ЯКИТ», очное отделение, группа КИСП-9-21, 4 курс', '3', 'Нормальный курс для общей грамотности по ИБ. Всё закрыл, документ выдали. Без восторга, но жаловаться не на что — ровно то, что обещали.', 't', '2026-04-14 16:23:28.161'),
('cmp67i07105lvlk9cyaat5g2s', 'cmp66xj6g00jrlktglfpxch9u', 'Ковалёв Никита Андреевич', 'НПОУ «ЯКИТ», очное отделение, группа КИСП-9-21, 4 курс', '3', 'Нормальный курс для общей грамотности по ИБ. Всё закрыл, документ выдали. Без восторга, но жаловаться не на что — ровно то, что обещали.', 't', '2026-04-09 18:17:08.925'),
('cmp67i07205lxlk9c0softw2l', 'cmp66xj6j00julktgmdiimj0m', 'Кулагин Роман Александрович', 'НПОУ «ЯКИТ», очное отделение, группа КИСП-9-21, 4 курс', '3', 'Нормальный курс для общей грамотности по ИБ. Всё закрыл, документ выдали. Без восторга, но жаловаться не на что — ровно то, что обещали.', 't', '2026-04-10 14:21:58.319'),
('cmp67i07205lzlk9cszdwm21i', 'cmp66xj6l00jxlktgvpioufwk', 'Малышев Александр Евгеньевич', 'НПОУ «ЯКИТ», очное отделение, группа КИСП-9-21, 4 курс', '5', 'Отлично: и фишинг, и устройства, и сети — без перегруза. Закрыл всё, сертификат приятный бонус. Одногруппникам уже скинул ссылку.', 't', '2026-04-11 18:02:46.938'),
('cmp67i07305m1lk9cjizw7c9n', 'cmp5md61i001xgnc0dxuc5vke', 'Трушков Дмитрий Александрович', 'Якутский гуманитарный колледж, группа КИ-24, 3 курс', '3', 'Прошла курс целиком. Нормально для программы: тесты честные, по практике комментарии полезные. Без «вау», но знания по ИБ реально прибавились.', 't', '2026-04-14 11:27:11.873'),
('cmp67i07505m9lk9chljq458y', 'cmp66xjcw00k9lktgoix1f5q7', 'Лаптев Никита Сергеевич', 'НПОУ «ЯКИТ», очное отделение, группа КИСП-9-22, 4 курс', '5', 'Очно на парах часто не хватает времени на «глубину» — здесь как раз она есть. Все модули закрыл, сертификат показал куратору. Топ.', 't', '2026-04-12 20:20:00.077'),
('cmp67i07305m3lk9cl2vp9gdd', 'cmp66xj6n00k0lktgvch68r54', 'Местников Артем Денисович', 'НПОУ «ЯКИТ», очное отделение, группа КИСП-9-21, 4 курс', '3', 'Прошла полностью на заочке. Нормально, без сюрпризов: тесты, практика, документ. Хотелось бы чуть больше голосовых/видео пояснений, но это вкусовщина.', 't', '2026-04-12 03:14:54.16'),
('cmp67i07405m5lk9c1qhfx3ty', 'cmp66xjco00k3lktgbfk820l0', 'Зорин Даниил Иванович', 'НПОУ «ЯКИТ», очное отделение, группа КИСП-9-22, 4 курс', '2', 'Дошёл до конца из-за зачёта. Полезные вещи есть, но подача местами сухая. Сертификат не компенсирует ощущение «протёрпел».', 't', '2026-04-13 14:50:12'),
('cmp67i07405m7lk9cces8c8hf', 'cmp66xjct00k6lktgvogzf3gl', 'Коротков Игорь Антонович', 'НПОУ «ЯКИТ», очное отделение, группа КИСП-9-22, 4 курс', '2', 'Сертификат есть, но вовлечение среднее: часть модулей ощущались как «прочитай и ответь». Для галочки подойдёт.', 't', '2026-04-12 10:49:07.373'),
('cmp67i07505mblk9ctbxuholw', 'cmp66xjcz00kclktgxhkngqcg', 'Мазуров Андрей Михайлович', 'НПОУ «ЯКИТ», очное отделение, группа КИСП-9-22, 4 курс', '4', 'Прошёл курс до конца, материал связный. Практика с обратной связью — сильная сторона. Не идеально, но уверенная четвёрка.', 't', '2026-04-11 02:31:49.885'),
('cmp67i07605mdlk9c67sd87sn', 'cmp66xjd100kflktgnl6a05sw', 'Мосеев Денис Ярославович', 'НПОУ «ЯКИТ», очное отделение, группа КИСП-9-22, 4 курс', '5', 'Сильная линейка модулей, всё связано с реальными ошибками пользователей. Прошёл до конца без «затыков». Сертификат — приятное подтверждение, что не зря вложился.', 't', '2026-04-14 14:50:02.049'),
('cmp67i07605mflk9csl3ikb48', 'cmp66xjd300kilktgqflu36cp', 'Огородов Данил Витальевич', 'НПОУ «ЯКИТ», очное отделение, группа КИСП-9-22, 4 курс', '5', 'Отличный порядок тем: от паролей до разборов. Практика после лекций — то, что нужно. Курс завершил, сертификатом доволен, преподавателю показал без стыда.', 't', '2026-04-10 06:09:33.87'),
('cmp67i07705mjlk9cks74lwyl', 'cmp66xjd800kolktgcmajav2w', 'Рачеев Никита Сергеевич', 'НПОУ «ЯКИТ», очное отделение, группа КИСП-9-22, 4 курс', '4', 'Хороший баланс теории и проверок. Все модули закрыл, к сертификату претензий нет. Звезду снял за то, что мобильная вёрстка местами прыгает.', 't', '2026-04-10 21:45:09.564'),
('cmp67i05n05gnlk9c6m7k1hm5', 'cmp66xi6h00cllktg5rcmrhnt', 'Канареев Руслан Юрьевич', 'НПОУ «ЯКИТ», заочное отделение, группа ЗКИСП-25, 1 курс', '4', 'Хороший рабочий курс: и лекции, и задания, и итоговый документ. Отняла балл только то, что к концу устала от однотипных формулировок в подсказках, но по содержанию всё честно и по делу.', 't', '2026-04-15 00:58:47.09');